import { z } from 'zod';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']),
  PORT: z.string().transform(Number),
  MONGODB_URI: z.string().url(),
  JWT_SECRET: z.string(),
  TELEGRAM_BOT_TOKEN: z.string().optional()
});

const env = envSchema.parse(process.env);

export default env;

import cron from 'node-cron';
import { TaskRepository } from '../repositories/task-repository';
import { NotificationService } from '../services/notification-service';
import { logger } from '../utils/logger';
import { catchAsyncErrors } from '../middleware/error-handler';

class SchedulingEngine {
  private taskRepo: TaskRepository;
  private notificationService: NotificationService;

  constructor() {
    this.taskRepo = new TaskRepository();
    this.notificationService = new NotificationService();
  }

  public start() {
    cron.schedule('* * * * *', catchAsyncErrors(this.runTasks));
  }

  private runTasks = async () => {
    const tasks = await this.taskRepo.findActiveTasks();
    for (const task of tasks) {
      if (task.shouldNotify()) {
        try {
          await this.notificationService.sendNotification(task);
          await this.taskRepo.logNotification(task.id, 'success');
        } catch (error) {
          logger.error(`Failed to send notification for task ${task.id}`, { error });
          await this.taskRepo.logNotification(task.id, 'failed', error.message);
        }
      }
    }
  };
}

export const schedulingEngine = new SchedulingEngine();

